import{_ as p,a as o,b as u,c as n,d as s}from"./TestNavigationButtons-2c2517a6.js";import{_ as a}from"./QuestionTemp4.vue_vue_type_script_setup_true_lang-d7e28324.js";import{S as c}from"./SeihoTestLayout-c0099714.js";import{o as y,c as v,w as r,b as i,a as e}from"./app-965211d2.js";import"./AdSenseUnit.vue_vue_type_script_setup_true_lang-a1090c43.js";const k={class:"bg-gray-100 text-gray-800 py-10"},b={class:"max-w-4xl mx-auto mt-4 space-y-2"},t="生命保険計理",l="2022年度 フォームB",w={__name:"Keiri2022b",setup(T){return(m,f)=>(y(),v(c,{title:t},{default:r(()=>[i("section",k,[e(p,{title:t,description:l}),i("div",b,[e(a,{questionNumber:1,title:t,subject:l,contents:[{answer:"0.96114",questionTitle:"生存率",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"生存率とは、「ある年齢の人が、次の年齢まで生き残る割合」のこと。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["生存率 = 期末の生存数 ÷ 期初の生存数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["生存率（60歳 → 65歳）","= 65歳の生存数 ÷ 60歳の生存数","= 88,751 ÷ 92,339 = 0.961143…"]},{type:"result",value:"▶ 答え 0.96114（小数第6位を四捨五入）"}]},{answer:"98,233",questionTitle:"生存数",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"「10年後に何人残るか」は、今の人数に10年間生き残る割合（生存率）を掛けることで求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formula",value:"N年後の生存者数 = 基準年齢の人数 × 生存率"},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"10年後の生存者数"},{type:"formulaBlock",value:["基準年齢（40歳）の人数 × 生存率（40歳 → 50歳）","= 100,000 × 96,319 ÷ 98,052 = 98,232.5…"]},{type:"result",value:"▶ 答え 98,233（小数第1位を四捨五入）"}]},{answer:"1.26",questionTitle:"平均余命",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"平均余命とは、その年齢の全員がこれから生きる年数を全部足して、今の人数で割ったもの。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["延べ生存年数 = 死亡数 × 平均生存年数","平均余命 = 延べ生存年数の合計 ÷ 生存者数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 各年齢の延べ生存年数"},{type:"note",value:"各年齢の死亡者は、その年齢内で平均<strong>0.5年</strong>生存したとみなして計算する。"},{type:"formulaBlock",value:["104歳：62.726 × 0.5 = 31.363 → 31.36","105歳：30.877 × 1.5 = 46.3155 → 46.32","106歳：13.8961 × 2.5 = 34.74025 → 34.74","107歳：5.6633 × 3.5 = 19.82155 → 19.82","108歳：2.0682 × 4.5 = 9.3069 → 9.31","109歳：0.9156 × 5.5 = 5.0358 → 5.04"]},{type:"text",value:"② 104歳～109歳の延べ生存年数の合計"},{type:"note",value:"104歳以上の全員が、合計で何年分生きたかを合算する。"},{type:"formulaBlock",value:["31.36 + 46.32 + 34.74 + 19.82 + 9.31 + 5.04 = 146.59"]},{type:"text",value:"③ 104歳の平均余命"},{type:"formulaBlock",value:["104歳～109歳の延べ生存年数の合計 ÷ 104歳の生存者数","= 146.59 ÷ 116.15","= 1.262…"]},{type:"result",value:"▶ 答え 1.26（小数第3位を四捨五入）"}]},{answer:"1,194,044",questionTitle:"保険金総額の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"1年定期保険では、1年間に死亡した人に保険金を支払う。したがって、まず死亡者全員に支払う保険金の合計額を出し、支払い時点を年央（期央）とみなして、期央払現価率で割り引いて現価を求める。"},{type:"note",value:"※期央払現価率とは、年の真ん中で支払われると仮定したときの割引係数。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["合計保険金額 = 保険金 × 死亡数","現価 = 合計保険金額 × 期央払現価率（利率1.0%）"]},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 合計保険金額"},{type:"formulaBlock",value:["保険金（300万円） × 死亡数（55歳男性）","= 3,000千円 × 400人","= 1,200,000千円"]},{type:"text",value:"② 現価（年央払）"},{type:"formulaBlock",value:["合計保険金額 × 期央払現価率（利率1.0%）","= 1,200,000千円 × 0.995037","= 1,194,044.4千円"]},{type:"result",value:"▶ 答え：1,194,044千円（千円未満四捨五入）"}]},{answer:"12,610",questionTitle:"純保険料",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"純保険料は、必要な保険金総額の現価を、加入者全員で負担する額。したがって、必要な現価を年始生存者数で割る。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["純保険料 = 必要な現価 ÷ 年始生存者数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["純保険料","= 必要な現価（問４の解） ÷ 55歳男性の年始生存者数","= 1,194,044千円 ÷ 94,704人","= 12,608.1…円"]},{type:"result",value:"▶ 答え 12,610円（10円未満四捨五入）"}]}],labels:["ア","ク","ウ","コ","カ"]}),e(a,{questionNumber:6,title:t,subject:l,contents:[{answer:"24,120",questionTitle:"複利計算",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"複利では、元金に利息が組み込まれながら増えていく。まず6か月後の元利合計を求め、そこから元金を差し引いて利息を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["元利合計 = 元金 × (1 + 利率)<sup>運用期間</sup>","利息 = 元利合計 − 元金"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["元金：2,000,000円","月利：0.2％ = 0.002","運用期間：6か月"]},{type:"text",value:"① 元利合計"},{type:"formulaBlock",value:["= 2,000,000円 × (1 + 0.002)<sup>6</sup>","= 2,000,000円 × 1.01206016","= 2,024,120.32円"]},{type:"text",value:"② 利息"},{type:"formulaBlock",value:["= 2,024,120.32円 − 2,000,000円","= 24,120.32円"]},{type:"result",value:"▶ 答え 24,120円（円未満四捨五入）"}]},{answer:"2,123,292",questionTitle:"複利計算（半年複利）",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"年利1.2％で半年複利の場合、半年ごとに0.6％ずつ増える。5年間では半年が10回あるため、半年利率で10回複利計算する。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["元利合計 = 元金 × (1 + 期間利率)<sup>複利回数</sup>"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["元金：2,000,000円","年利：1.2％","半年利率：= 1.2％ ÷ 2 = 0.6％ = 0.006","複利回数：= 5年 × 年2回 = 10回"]},{type:"formulaBlock",value:["元利合計","= 2,000,000円 × (1 + 0.006)<sup>10</sup>","= 2,000,000円 × 1.0616461","= 2,123,292.2円"]},{type:"result",value:"▶ 答え 2,123,292円（円未満四捨五入）"}]},{answer:"1.51",questionTitle:"実利率",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"実利率とは、1年間に実際どれだけ増えるかを示す利率。名称利率が年率でも、年に複数回利息が付く場合は、その回数分だけ複利計算する。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["実利率 =（ 1 + 名称利率 ÷ 転化回数）<sup>転化回数</sup> - 1"]},{type:"note",value:"転化回数：1年間に利息を元金に繰り入れる回数"},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 1回あたりの利率"},{type:"formulaBlock",value:["= 0.015 ÷ 4","= 0.00375"]},{type:"text",value:"② 実利率"},{type:"formulaBlock",value:["= (1 + 0.00375)<sup>4</sup> − 1","= 1.015084 − 1","= 0.015084 = 1.5084％"]},{type:"result",value:"▶ 答え 1.51％（小数第3位を四捨五入）"}]},{answer:"1.33",questionTitle:"年平均利回り",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"まず、5年間の複利でどれだけ増えたか（総利回り）を求める。その後、それを5年で平均したものが年平均利回り。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["総利回り = (1 + 複利利率)<sup>期間</sup> − 1","年平均利回り = 総利回り ÷ 期間"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["複利利率：1.3％ = 0.013","投資期間：5年"]},{type:"text",value:"① 総利回り"},{type:"formulaBlock",value:["= (1 + 0.013)<sup>5</sup> − 1","= 1.066712 − 1","= 0.066712"]},{type:"text",value:"② 年平均利回り"},{type:"formulaBlock",value:["= 0.066712 ÷ 5","= 0.0133424 = 1.33424％"]},{type:"result",value:"▶ 答え 1.33％（小数第3位を四捨五入）"}]},{answer:"1,902,931",questionTitle:"現在必要資金の計算",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"将来200万円を得るために、今いくら必要かを求める問題。将来価値がわかっているので、複利を逆算（割り戻す）して現在価値を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["現在価値 = 将来価値 ÷ (1 + 利率)<sup>期間</sup>"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["将来価値：2,000,000円","年利率：1.0％ = 0.01","期間：5年"]},{type:"formulaBlock",value:["現在価値","= 2,000,000 ÷ (1 + 0.01)<sup>5</sup>","= 2,000,000 ÷ 1.051010","= 1,902,931.3…"]},{type:"result",value:"▶ 答え 1,902,931円（円未満四捨五入）"}]}],labels:["オ","コ","ウ","イ","ク"]}),e(o,{questionNumber:3,questionTitle:"責任準備金の積立に関する法的規制-①",title:t,subject:l,contents:["年金","負債","平準純保険料式","ソルベンシー・マージン","ストレステスト"],labels:["ア","エ","コ","キ","オ"]}),e(o,{questionNumber:4,questionTitle:"責任準備金の積立に関する法的規制-②",title:t,subject:l,contents:["未経過保険料","危険保険料","算出方法書","最低保証リスク","保険計理人"],labels:["エ","コ","イ","ク","ア"]}),e(a,{questionNumber:21,title:t,subject:l,contents:[{answer:"1,529,227千円",questionTitle:"死亡保険金の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"保険期間（45〜49歳）の各年齢で死亡した場合、死亡保険金が支払われる。支払いは年央（期央）と仮定されるため、各年齢の「死亡保険金 × 死亡数」を期央払現価率で割り引き、現価を合計する。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["各年齢の死亡保険金現価 = 死亡保険金 × 死亡数 × 期央払現価率","死亡保険金現価の合計 = 各年齢の死亡保険金現価の合計"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["死亡保険金：150万円 = 1,500千円","保険期間：5年（45〜49歳）","支払い：年央（期央）と仮定"]},{type:"text",value:"① 各年齢の死亡保険金現価"},{type:"formulaBlock",value:["45歳：1,500千円 × 172 × 0.995037 = 256,720千円","46歳：1,500千円 × 189 × 0.985185 = 279,300千円","47歳：1,500千円 × 208 × 0.975431 = 304,334千円","48歳：1,500千円 × 228 × 0.965773 = 330,294千円","49歳：1,500千円 × 250 × 0.956211 = 358,579千円"]},{type:"text",value:"② 合計"},{type:"formulaBlock",value:["死亡保険金現価の合計","= 256,720 + 279,300 + 304,334 + 330,294 + 358,579","= 1,529,227千円"]},{type:"result",value:"▶ 答え 1,529,227千円"}]},{answer:"137,466,380千円",questionTitle:"満期保険金の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"満期保険金は、保険期間満了時（5年後）に生存している人に支払われる。したがって、まず 5年後の生存者数 × 保険金額 で将来の支払総額を求め、それを 期末払現価率 で割り引いて現価を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["満期保険金の現価 = 5年後の生存者数 × 保険金額 × 期末払現価率（5年）"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["保険金額：150万円 = 1,500千円","5年後（50歳）の生存数：96,319人","5年の期末払現価率：0.951466"]},{type:"formulaBlock",value:["満期保険金の現価","= 96,319 × 1,500 × 0.951466","= 137,466,380.481千円"]},{type:"result",value:"▶ 答え 137,466,380千円（千円未満四捨五入）"}]},{answer:"3,651,225千円",questionTitle:"予定事業費の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"予定事業費が「保険金1000円につき25円」と与えられているので、まず 1人あたりの予定事業費を求める。その後、加入時（45歳）の生存者数を掛けて、全体の予定事業費（現価）を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["1人あたりの予定事業費 = 保険金額 ×（25 ÷ 1000）","予定事業費の現価（合計） = 1人あたりの予定事業費 × 加入時の生存者数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["保険金額：150万円 = 1,500千円","予定事業費：保険金1000円につき25円 = 25 ÷ 1000","45歳の生存数：97,366人"]},{type:"text",value:"① 1人あたりの予定事業費"},{type:"formulaBlock",value:["= 1,500千円 ×（25 ÷ 1000）","= 1,500 × 0.025","= 37.5千円"]},{type:"text",value:"② 予定事業費の現価（合計）"},{type:"formulaBlock",value:["= 37.5千円 × 97,366人","= 3,651,225千円"]},{type:"result",value:"▶ 答え 3,651,225千円（千円未満四捨五入）"}]},{answer:"300,030円",questionTitle:"養老保険の年払営業保険料",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"年払営業保険料 P は、収支相当の原則（収入現価=支出現価）で求める。"},{type:"text",value:"収入現価：各年齢で生存している人が払う保険料 P を、期始払として現価に直して合計する"},{type:"text",value:"支出現価：死亡保険金・満期保険金・予定事業費の現価を合計する（問21〜23の結果）"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["収支相当の原則：収入現価 = 支出現価","各年齢の収入現価（期始払） = 生存数 × P × 期始払現価率","支出現価 = 死亡保険金現価 + 満期保険金現価 + 予定事業費現価"]},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 収入現価（45〜49歳、期始払）"},{type:"formulaBlock",value:["45歳：P × 97,366 × 1.000000 = 97,366P","46歳：P × 97,194 × 0.990099 = 96,232P","47歳：P × 97,005 × 0.980296 = 95,094P","48歳：P × 96,798 × 0.970590 = 93,951P","49歳：P × 96,569 × 0.960980 = 92,801P"]},{type:"formulaBlock",value:["収入現価の合計","= 97,366P + 96,232P + 95,094P + 93,951P + 92,801P","= 475,444P"]},{type:"text",value:"② 支出現価（問21〜23より）"},{type:"formulaBlock",value:["死亡保険金の現価（問21）= 1,529,227千円","満期保険金の現価（問22）= 137,466,380千円","予定事業費の現価（問23）= 3,651,225千円"]},{type:"formulaBlock",value:["支出現価","= 1,529,227 + 137,466,380 + 3,651,225","= 142,646,832千円 = 142,646,832,000円"]},{type:"text",value:"③ 収支相当の原則より P を求める"},{type:"formulaBlock",value:["収入現価 = 支出現価 より","475,444P = 142,646,832,000円","P = 142,646,832,000円 ÷ 475,444","P = 300,028…円"]},{type:"result",value:"▶ 答え 300,030円（10円未満四捨五入）"}]}],labels:["イ","ア","ウ","ア"]}),e(u,{questionNumber:25,title:t,subject:l,questionTitle:"契約者配当金の分配・支払方法",contents:["年払保険料 → 一時払保険料","その年度の保険料にまとめて充当 → 払込回数に等分し、毎回の保険料に充当","正しい"]}),e(u,{questionNumber:26,title:t,subject:l,questionTitle:"営業保険料の計算上配慮する点",contents:["正しい","営業保険料を安くすることを意味する → 営業保険料を安くすることを必ずしも意味していない","正しい"]}),e(u,{questionNumber:27,title:t,subject:l,questionTitle:"純保険料式保険料積立金",contents:["正しい","定期保険、高倍率定期付養老保険 → 定期保険（高倍率定期付養老保険は含まない）","正しい"]}),e(u,{questionNumber:28,title:t,subject:l,questionTitle:"契約変更",contents:["正しい","正しい","満期時に残額を払い戻さない → 残額があれば払い戻す"]}),e(u,{questionNumber:29,title:t,subject:l,questionTitle:"契約者配当の意義と割当",contents:["正しい","有配当保険より高くなる → 安くなる","正しい"]}),e(u,{questionNumber:30,title:t,subject:l,questionTitle:"事業年度末責任準備金",contents:["正しい","正しい","保険リスクのみ → 保険リスク、第三分野保険の保険リスク、予定利率リスクおよび最低保証リスク"]}),e(n,{questionNumber:31,title:t,subject:l,items:[{questionTitle:"平均余命・平均寿命",content:"正しい"},{questionTitle:"生命保険契約と年齢",content:"正しい"},{questionTitle:"予定利率",content:"正しい"},{questionTitle:"現価",content:"期始払現価 → 期末払現価"},{questionTitle:"平準保険料",content:"正しい"},{questionTitle:"責任準備金",content:"保険期間の前半 → 後半"},{questionTitle:"解約返戻金の算式",content:"チルメル式保険料積立金 → 解約までの経過期間に応じた純保険料式保険料積立金"},{questionTitle:"剰余金におけるその他の損益",content:"正しい"},{questionTitle:"変額保険の運用リスク",content:"生命保険会社 → 契約者"},{questionTitle:"特別勘定の位置付け",content:"保険業法上の規定によるものでなく → 保険業法上の規定によるもの"},{questionTitle:"死亡表の種類",label:"ウ",content:"毎年"},{questionTitle:"資産の平均利回り",label:"イ",content:"年平残方式"},{questionTitle:"収支相当の原則",label:"ア",content:"現価"},{questionTitle:"純保険料の変化",label:"ウ",content:"低くなる"},{questionTitle:"解約返戻金",label:"エ",content:"契約者貸付"},{questionTitle:"加入年齢方式による転換",label:"オ",content:""},{questionTitle:"貯蓄保険料の計算式",label:"オ",content:""},{questionTitle:"配当準備金繰入",label:"ウ",content:"20%"},{questionTitle:"変額保険の仕組み",label:"ア",content:"超過資産"},{questionTitle:"団体年金の保険料計算",label:"ウ",content:"通常保険料"}]})]),e(s,{"previous-route":"keiri2022a","next-route":"keiri2022c"})])]),_:1}))}};export{w as default};
